let out = [{"label":"Do not use a dictionnary", "id":"0"}]
const courseLang = $('Call \'[SUB] Localisation - HTML Course get\'').first().json.infos.language
const targetLang = $('Params').first().json['Supported Languages'].filter(x=>x.label == $('Form choose lang').first().json['Target language'])[0].name

$input.first().json.glossaries.forEach(glo=>{
  glo.dictionaries.forEach(dic=>{
    if(dic.source_lang == courseLang && dic.target_lang == targetLang){
      out.unshift({'label':glo.name, "id":glo.glossary_id})
    }
  })
})

return {dictionnaries:out, targetLang:targetLang, sourceLang:courseLang}

