const dicLabel = $('Form Choose dict').first().json.Dictionnary
const matched = $('Filter dicts').first().json.dictionnaries.filter(x=>x.label == dicLabel)
if(matched[0].id == 0){
  return {"dicId":null}
} else {
  return {"dicId":matched[0].id}
}

const input = $input.all()
let filesData = [] // {name:file.txt,data:string,mime:text/whatevs}

input.forEach(item=>{
  filesData.push({
    name:`CAPTION_NOTES_${item.json.title}.txt`,
    data:item.json.editors_notes,
    mime: "text/plain"
  })
  filesData.push({
    name:`CAPTION_AUDIT_${item.json.title}.txt`,
    data:item.json.audit,
    mime: "text/plain"
  })
  const ext = item.json.original.toLocaleLowerCase().startsWith("webvtt")? "vtt":"srt"
  filesData.push({
    name:`CAPTION_TRANSLATED_${item.json.title}.${ext}`,
    data:item.json.translated,
    mime: "text/plain"
  })
  filesData.push({
    name:`CAPTION_ORIGINAL_${item.json.title}.${ext}`,
    data:item.json.original,
    mime: "text/plain"
  })
})

const binaryData = {};

filesData.forEach((file) => {
  binaryData[file.name] = {
    data: Buffer.from(file.data).toString('base64'),
    fileName: file.name,
    mimeType: file.mime,
  };
});

return [
  {
    json: {
      filesCount: filesData.length,
    },
    binary: binaryData,
  }
];

let emailBuffer = `<p>Hello!<br>You made a request to translate the course:<br><strong>${$('Call \'[SUB] Localisation - HTML Course get\'').first().json.infos.title}</strong>:</p>`

emailBuffer += "<ul>"

if ($('Params').first().json.Options.translateHTML) {
  emailBuffer += `<li><p>You asked for the course text to be translated, you can find the original, draft, proffread, audit and QA notes for each chapter inside the attached zip file.</p></li>`
}

if ($('Params').first().json.Options.auditLinks) {
  emailBuffer += `<li><p>You asked for an audition of the links inside the course text, you can find the results in the attached zip file.</p></li>`
}

if ($('Params').first().json.Options.translateCaptions) {
  emailBuffer += `<li><p>You asked for the captions to be translated, you can find them in the attached zip file, which contains the original, translated captions, audit, QA and editor's notes for each one.</p></li>`
}

if ($('Params').first().json.Options.copyVideos) {
  emailBuffer+= `<li><p>You asked for the course videos to be copied in Iconik, here is the link: <a href="${$('Call \'[SUB - Course Localisation] Copy videos to iconik\'').first().json['Iconik URL']}" target="_blank">Iconik</a><p></li>`
}

emailBuffer += "</ul>"


return {"emailBody": emailBuffer}

let filesData = []//{name,data,type}
let test

if($('Params').first().json.Options.translateHTML){
  const fields = Object.keys($('Prepare chapter files').first().binary)
  fields.forEach(field=>{
    const file = $('Prepare chapter files').first().binary[field]
    filesData.push({
      data: file.data,
      type: file.mimeType,
      name: file.fileName,
    })
    test = file
  })
}

if($('Params').first().json.Options.auditLinks){
  filesData.push({
    name: "Links_audit.html",
    data: Buffer.from($('Links audit html').first().json.html).toString('base64'),
    type: "text/html"
  })
}

if($('Params').first().json.Options.translateCaptions){
  const fields = Object.keys($('Prepare caption files').first().binary)
  fields.forEach(field=>{
    const file = $('Prepare caption files').first().binary[field]
    filesData.push({
      data: file.data,
      type: file.mimeType,
      name: file.fileName,
    })
  })
}

const binaryData = {}

filesData.forEach((file) => {
  binaryData[file.name] = {
    data: file.data,
    fileName: file.name,
    mimeType: file.type,
  };
});

return [
  {
    json: {
      filesCount: filesData.length,
      test: test
    },
    binary: binaryData,
  }
];

let filesData = [] // {fileName, data, mimeType}

filesData.push({
  fileName: "COURSE_draft.html",
  data: $input.first().json.singlePageDraft,
  mimeType: "text/html"
})

filesData.push({
  fileName: "COURSE_original.html",
  data: $('Call \'[SUB] Localisation - HTML Course get\'').first().json.singlePageHTML,
  mimeType: "text/html"
})

$input.first().json.chapters.forEach(chapter=>{
  const partChapter = `P${chapter.partIndex}C${chapter.chapterIndex}`
  filesData.push({
    fileName: `CHAPTER_${partChapter}_original.html`,
    data: chapter.original,
    mimeType: "text/html"
  })
  filesData.push({
    fileName: `CHAPTER_${partChapter}_audit.txt`,
    data: chapter.audit,
    mimeType: "text/plain"
  })
  filesData.push({
    fileName: `CHAPTER_${partChapter}_draft.html`,
    data: chapter.draft,
    mimeType: "text/html"
  })
  filesData.push({
    fileName: `CHAPTER_${partChapter}_proofread.html`,
    data: chapter.proofread,
    mimeType: "text/html"
  })
  filesData.push({
    fileName: `CHAPTER_${partChapter}_editors_notes.txt`,
    data: chapter.editors_notes,
    mimeType: "text/plain"
  })
  filesData.push({
    fileName: `CHAPTER_${partChapter}_qa.txt`,
    data: chapter.qa,
    mimeType: "text/plain"
  })
})

const binaryData = {};
filesData.forEach((file) => {
  binaryData[file.fileName] = {
    data: Buffer.from(file.data).toString('base64'),
    fileName: file.fileName,
    mimeType: file.mimeType,
  };
});

return [
  {
    json: {
      filesCount: filesData.length,
    },
    binary: binaryData,
  }
];

